import{_ as a,o as t,c as n,ag as s}from"./chunks/framework.BZohXCq9.js";const h=JSON.parse('{"title":"Bamdra | AI That Belongs In Real Work","titleTemplate":false,"description":"Bamdra imagines AI that enters real work, expands human reach, and reshapes workflows. Discover bamdra-openclaw-memory, the durable memory system for OpenClaw.","frontmatter":{"layout":"home","title":"Bamdra | AI That Belongs In Real Work","titleTemplate":false,"description":"Bamdra imagines AI that enters real work, expands human reach, and reshapes workflows. Discover bamdra-openclaw-memory, the durable memory system for OpenClaw.","hero":{"name":"Bamdra","text":"AI takes flight from human intent, and returns with amplified insight.","tagline":"Bamdra is inspired by the bamboo dragonfly: launched by human intent, lifted by intelligence, and returned to human hands with greater perspective. We are building a three-plugin OpenClaw memory suite that does not stay in demos, but enters real work and changes how people move through complex workflows.","image":{"src":"/images/Gemini_Generated_Image_fug6l2fug6l2fug6.jpg","alt":"Bamdra product hero visual"},"actions":[{"theme":"brand","text":"Explore bamdra-openclaw-memory","link":"/guide/openclaw-topic-memory"},{"theme":"alt","text":"Download Package","link":"/guide/downloads"}]},"features":[{"icon":"🚀","title":"Built for real work","details":"We focus on the moment AI stops being a novelty and starts changing how teams actually operate."},{"icon":"🧠","title":"Durable memory for OpenClaw","details":"Recover topic branches, persist stable facts, and keep context short enough for production use."},{"icon":"⚙️","title":"Ready to enter workflow","details":"Deploy with a real release package, practical configuration, and installation guidance aligned with OpenClaw runtime behavior."},{"icon":"📈","title":"More than implementation","details":"The real goal is not just technical capability, but visible change in continuity, collaboration, and the structure of daily work."}]},"headers":[],"relativePath":"index.md","filePath":"index.md","lastUpdated":null}'),i={name:"index.md"};function o(r,e,l,c,d,p){return t(),n("div",null,[...e[0]||(e[0]=[s('<div class="home-shell"><section class="home-panel hero-story"><div><h2>The meaning of Bamdra</h2><p>Bamdra is named after the bamboo dragonfly, 竹蜻蜓. A bamboo dragonfly rises because human hands give it force. Once airborne, it reaches a higher view and travels farther than the hand alone can. Yet it is never detached from people; its value is completed only when it returns to human hands with a broader perspective. That is how we think about AI: launched by human intent, expanded by machine capability, and ultimately accountable to human judgment.</p></div><div class="story-accent"><p class="accent-kicker">Vision</p><h3>We want AI to stop hovering at the edge of work and start reshaping how work is done.</h3><p>Not by replacing people, but by helping people hold more context, move faster across complexity, and keep better continuity in the moments where work usually breaks apart.</p></div></section><section class="home-panel"><h2>Why teams look at Bamdra now</h2><div class="signal-grid"><div class="signal-item"><strong>OpenClaw</strong><span>Focused product fit from day one, with a dedicated memory system built specifically for OpenClaw workflows.</span></div><div class="signal-item"><strong>SQLite-first</strong><span>Simple deployment, predictable persistence, and fast retrieval without introducing unnecessary infrastructure.</span></div><div class="signal-item"><strong>Workflow change</strong><span>What matters is not just that AI can do something, but that it changes the rhythm, continuity, and leverage of everyday work.</span></div><div class="signal-item"><strong>Human return</strong><span>AI should always come back to human judgment, human goals, and human accountability, even after it has expanded what is possible.</span></div></div></section><section class="home-panel"><div class="section-heading"><p class="accent-kicker">Product Suite</p><h2>Three plugins, one continuity-first memory stack</h2><p>Bamdra now ships as a three-plugin public suite. All three plugins can run independently, while the main memory plugin can also auto-provision its identity companion during install.</p></div><div class="signal-grid"><div class="signal-item"><strong>bamdra-openclaw-memory</strong><span>The main runtime for topic continuity, compact context assembly, fact storage, and long-session recovery in OpenClaw.</span></div><div class="signal-item"><strong>bamdra-user-bind</strong><span>The identity and profile plugin. It resolves raw channel identities into stable user boundaries, and it can run on its own or be auto-provisioned by the main memory plugin.</span></div><div class="signal-item"><strong>bamdra-memory-vector</strong><span>The optional semantic retrieval layer. It adds Markdown plus vector recall without turning the suite into a heavy external memory stack.</span></div><div class="signal-item"><strong>Why the split matters</strong><span>Separate repositories, packages, and release roles make deployment clearer, security boundaries safer, and future iteration easier.</span></div></div></section><section class="home-panel product-card"><div class="product-copy"><p class="accent-kicker">Suite Entry</p><h2>bamdra-openclaw-memory is the main entry point</h2><p>bamdra-openclaw-memory gives OpenClaw durable memory for long-running sessions. It separates conversation branches, saves reusable facts, refreshes summaries, and keeps the active prompt compact enough to stay practical in production.</p><p>`bamdra-openclaw-memory` can run independently. When it is installed through npm, it can also auto-provision <code>bamdra-user-bind</code> if that dependency is not already materialized in the local OpenClaw extensions directory.</p><p><code>bamdra-memory-vector</code> stays independent and optional on purpose, so teams can add semantic retrieval only when they actually want it.</p><div class="inline-actions"><a class="contact-link" href="/guide/products">Browse All Products</a><a class="contact-link" href="https://github.com/bamdra">Open GitHub</a></div></div><div class="product-meta"><ul><li><span>Repository</span><strong>bamdra/bamdra-openclaw-memory</strong></li><li><span>Primary value</span><strong>Continuity without prompt bloat</strong></li><li><span>Auto companion</span><strong>bamdra-user-bind</strong></li><li><span>Optional enhancement</span><strong>bamdra-memory-vector</strong></li><li><span>Deployment mode</span><strong>SQLite-native, user-aware orchestration</strong></li></ul></div></section><section class="home-panel home-columns"><div class="info-card"><p class="accent-kicker">Use Cases</p><h3>Built for nonlinear work</h3><ul class="clean-list"><li>Product operations that jump between incidents, planning, and handoff notes.</li><li>Developer copilots that must preserve project constraints across long sessions.</li><li>Knowledge workflows where stable facts need to survive restarts and topic drift.</li></ul></div><div class="info-card"><p class="accent-kicker">What Changes</p><h3>Not just deployment, but a new working pattern</h3><ul class="clean-list"><li>Less repetition when teams return to paused work.</li><li>Stronger continuity across interruptions, detours, and restarts.</li><li>A more durable way to carry decisions, paths, constraints, and preferences through long workflows.</li></ul></div></section><section class="home-panel download-panel"><div><p class="accent-kicker">Get Started</p><h2>Download the current release</h2><p>Start from the actual packaged release, then use the installation and runtime guidance in this site to wire it into OpenClaw correctly.</p></div><div class="inline-actions"><a class="contact-link" href="/downloads/bamdra-openclaw-memory-v0.3.1.zip">Download v0.3.1</a><a class="contact-link" href="/guide/downloads">Open Download Center</a></div></section></div>',1)])])}const u=a(i,[["render",o]]);export{h as __pageData,u as default};
